const reportForm = document.getElementById("reportForm");
const statusEl = document.getElementById("status");
const previewCodeEl = document.getElementById("previewCode");
const pdfRenderRoot = document.getElementById("pdfRenderRoot");

const loginGate = document.getElementById("loginGate");
const reportApp = document.getElementById("reportApp");
const loginForm = document.getElementById("loginForm");
const loginUser = document.getElementById("loginUser");
const loginPass = document.getElementById("loginPass");
const loginStatus = document.getElementById("loginStatus");
const clienteSelect = document.getElementById("clienteSelect");
const clienteManual = document.getElementById("clienteManual");
const rucInput = document.getElementById("rucInput");
const direccionInput = document.getElementById("direccionInput");
const previewPdfBtn = document.getElementById("previewPdfBtn");
const pdfPreviewPanel = document.getElementById("pdfPreviewPanel");
const pdfPreviewGrid = document.getElementById("pdfPreviewGrid");
const downloadFromPreviewBtn = document.getElementById("downloadFromPreviewBtn");

const AUTH_USER = "admin";
const AUTH_PASS = "glaucusvma";
const AUTH_KEY = "glaucus_report_auth";

const SAFE_PDF_LOGO_DATA_URI = "data:image/png;base64,";
let pdfLogoSrc = SAFE_PDF_LOGO_DATA_URI;

const CLIENTES = [
  { nombre: "BOMBONERIA DI PERUGIA S.A.C.", ruc: "20126426870", direccion: "AV. LA PAZ NRO. 2350 URB. MIRAMAR - LIMA - SAN MIGUEL" },
  { nombre: "FRIOPAN S.A.C.", ruc: "20468826951", direccion: "MZA. J LOTE. 6-B URB. SAN JUAN BAUTISTA (ALT NUEVA CARCEL DE MUJERES CHORRILLOS) - LIMA - CHORRILLOS" },
  { nombre: "RESTAURANTECH PERU S.R.L.", ruc: "20607486990", direccion: "JR. MANUEL GONZALES PRADA 1035 URB. SAN JORGE - LIMA - SURQUILLO" }
];

const state = {
  cargo: [],
  ph: [],
  grasa: [],
  obs: []
};

const counterMemory = {};
const authMemory = {};
const MAX_IMAGE_DIMENSION = 1600;
const IMAGE_QUALITY = 0.78;
let lastGeneratedPdfBlob = null;
let lastGeneratedFileName = "";

function setStatus(message, type = "") {
  if (!statusEl) return;
  statusEl.textContent = message;
  statusEl.classList.remove("ok", "error");
  if (type) statusEl.classList.add(type);
}

function setLoginStatus(message, type = "") {
  if (!loginStatus) return;
  loginStatus.textContent = message;
  loginStatus.classList.remove("ok", "error");
  if (type) loginStatus.classList.add(type);
}

function storageGet(key) {
  try {
    return localStorage.getItem(key);
  } catch {
    return Object.prototype.hasOwnProperty.call(counterMemory, key) ? counterMemory[key] : null;
  }
}

function storageSet(key, value) {
  try {
    localStorage.setItem(key, value);
  } catch {
    counterMemory[key] = value;
  }
}

function sessionGet(key) {
  try {
    return sessionStorage.getItem(key);
  } catch {
    return Object.prototype.hasOwnProperty.call(authMemory, key) ? authMemory[key] : null;
  }
}

function sessionSet(key, value) {
  try {
    sessionStorage.setItem(key, value);
  } catch {
    authMemory[key] = value;
  }
}

function isAuthenticated() {
  return sessionGet(AUTH_KEY) === "1";
}

function enableReportApp() {
  if (loginGate) loginGate.style.display = "none";
  if (reportApp) reportApp.style.display = "block";
  updatePreviewCode();
}

function guardAccess() {
  if (isAuthenticated()) {
    enableReportApp();
    return;
  }

  if (loginGate) loginGate.style.display = "block";
  if (reportApp) reportApp.style.display = "none";
}

function getMonthKey() {
  const now = new Date();
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}`;
}

function getCounterKey(monthKey) {
  return `glaucus_report_counter_${monthKey}`;
}

function getNextCounterPreview(monthKey) {
  const key = getCounterKey(monthKey);
  const raw = storageGet(key);
  const current = raw ? Number(raw) : 0;
  return current + 1;
}

function formatCode(monthKey, counter) {
  const [year, month] = monthKey.split("-");
  return `GL-${year}-${month}-${String(counter).padStart(3, "0")}`;
}

function sanitizeFilePart(value) {
  return value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-zA-Z0-9_-]+/g, "_")
    .replace(/^_+|_+$/g, "") || "Cliente";
}

function updatePreviewCode() {
  if (!previewCodeEl) return;
  const monthKey = getMonthKey();
  const nextCounter = getNextCounterPreview(monthKey);
  previewCodeEl.textContent = formatCode(monthKey, nextCounter);
}

function populateClientes() {
  if (!clienteSelect) return;

  CLIENTES.forEach((cliente, index) => {
    const option = document.createElement("option");
    option.value = cliente.nombre;
    option.textContent = cliente.nombre;
    option.dataset.index = String(index);
    clienteSelect.appendChild(option);
  });
}

function fillClienteData() {
  if (!clienteSelect || !rucInput || !direccionInput) return;

  const selectedName = clienteSelect.value;
  const cliente = CLIENTES.find((item) => item.nombre === selectedName);

  if (!cliente) {
    rucInput.value = "";
    direccionInput.value = "";
    return;
  }

  rucInput.value = cliente.ruc;
  direccionInput.value = cliente.direccion;
}

function getClienteFinal() {
  const manualName = (clienteManual?.value || "").trim();
  const selectedName = (clienteSelect?.value || "").trim();
  return manualName || selectedName;
}

function syncClienteRequiredRule() {
  if (!clienteSelect || !clienteManual) return;
  const hasManual = clienteManual.value.trim().length > 0;
  clienteSelect.required = !hasManual;
}

function preloadPdfLogo() {
  pdfLogoSrc = SAFE_PDF_LOGO_DATA_URI;
}

async function compressImage(file) {
  const objectUrl = URL.createObjectURL(file);

  try {
    const image = await new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = objectUrl;
    });

    const ratio = Math.min(1, MAX_IMAGE_DIMENSION / Math.max(image.width, image.height));
    const width = Math.max(1, Math.round(image.width * ratio));
    const height = Math.max(1, Math.round(image.height * ratio));

    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;

    const ctx = canvas.getContext("2d", { alpha: false });
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, width, height);
    ctx.drawImage(image, 0, 0, width, height);

    return canvas.toDataURL("image/jpeg", IMAGE_QUALITY);
  } finally {
    URL.revokeObjectURL(objectUrl);
  }
}

function renderPreviews(sectionKey) {
  const container = document.getElementById(`preview-${sectionKey}`);
  if (!container) return;

  const items = state[sectionKey];
  container.innerHTML = "";

  items.forEach((item, index) => {
    const card = document.createElement("article");
    card.className = "preview-item";

    const img = document.createElement("img");
    img.src = item.dataUrl;
    img.alt = `Vista previa ${sectionKey} ${index + 1}`;

    const input = document.createElement("input");
    input.type = "text";
    input.className = "desc-input";
    input.placeholder = "Descripcion de la imagen";
    input.value = item.description;
    input.addEventListener("input", (event) => {
      item.description = event.target.value;
    });

    const tools = document.createElement("div");
    tools.className = "preview-tools";

    const remove = document.createElement("button");
    remove.type = "button";
    remove.className = "remove-btn";
    remove.textContent = "Eliminar";
    remove.addEventListener("click", () => {
      state[sectionKey].splice(index, 1);
      renderPreviews(sectionKey);
    });

    tools.appendChild(remove);
    card.append(img, input, tools);
    container.appendChild(card);
  });
}

function bindUploaders() {
  document.querySelectorAll(".uploader").forEach((uploader) => {
    const sectionKey = uploader.dataset.key;
    const max = Number(uploader.dataset.max);
    const fileInput = uploader.querySelector(".file-input");

    fileInput.addEventListener("change", async (event) => {
      const files = Array.from(event.target.files || []);
      event.target.value = "";

      const remaining = max - state[sectionKey].length;
      if (remaining <= 0) {
        setStatus(`La seccion ${sectionKey} ya alcanzo el maximo permitido.`, "error");
        return;
      }

      const toProcess = files.slice(0, remaining);

      for (const file of toProcess) {
        try {
          const dataUrl = await compressImage(file);
          state[sectionKey].push({ dataUrl, description: "" });
        } catch {
          setStatus(`No se pudo procesar la imagen ${file.name}.`, "error");
        }
      }

      renderPreviews(sectionKey);
    });
  });
}

function requireCargoImage() {
  if (state.cargo.length === 0) {
    setStatus("Debes subir la foto de cargo obligatoria.", "error");
    return false;
  }
  return true;
}

function makeHeader(reportCode, formattedDate) {
  const header = document.createElement("header");
  header.className = "pdf-header";

  header.innerHTML = `
    <div>
      <img src="${pdfLogoSrc}" alt="Logo" class="pdf-logo" />
    </div>
    <div>
      <h1 class="pdf-brand-title">GLAUCUS</h1>
      <p class="pdf-brand-sub">Tecnologia e innovacion en tratamiento de aguas</p>
      <p class="pdf-brand-mini">Reporte tecnico de control y monitoreo</p>
    </div>
    <div class="pdf-meta">
      <div><b>Codigo:</b> ${reportCode}</div>
      <div><b>Fecha:</b> ${formattedDate}</div>
    </div>
  `;

  return header;
}

function makeImageBlock(item, options = {}) {
  const block = document.createElement("article");
  block.className = "pdf-image-block";

  const img = document.createElement("img");
  img.className = `pdf-image ${options.tall ? "tall" : ""}`.trim();
  img.src = item.dataUrl;
  img.alt = "Evidencia";

  const caption = document.createElement("p");
  caption.className = "pdf-caption";
  caption.textContent = item.description?.trim() || options.defaultCaption || "Sin descripcion";

  block.append(img, caption);
  return block;
}

function makeEmptyBlock(message) {
  const empty = document.createElement("div");
  empty.className = "pdf-empty";
  empty.textContent = message;
  return empty;
}

function makePageBase(reportCode, formattedDate) {
  const page = document.createElement("section");
  page.className = "pdf-page";

  const header = makeHeader(reportCode, formattedDate);
  const content = document.createElement("div");
  content.className = "pdf-content";

  const footer = document.createElement("footer");
  footer.className = "pdf-footer";
  footer.innerHTML = `
    <span class="pdf-footer-company">Tellus Engineer S.A.C.</span>
    <span class="pdf-footer-ruc">RUC 20610307087</span>
    <span class="pdf-footer-page">Pagina 1 de 1</span>
  `;

  page.append(header, content, footer);
  return { page, content };
}

function buildPageOne(data, reportCode, formattedDate) {
  const { page, content } = makePageBase(reportCode, formattedDate);

  const title = document.createElement("h2");
  title.className = "pdf-section-title";
  title.textContent = "Datos principales";

  const grid = document.createElement("div");
  grid.className = "pdf-data-grid";

  const fields = [
    ["Cliente", data.cliente],
    ["RUC", data.ruc],
    ["Direccion", data.direccion],
    ["Tecnico", data.tecnico]
  ];

  fields.forEach(([label, value]) => {
    const card = document.createElement("div");
    card.className = "pdf-data-card";
    card.innerHTML = `<b>${label}</b><span>${value}</span>`;
    grid.appendChild(card);
  });

  const cargoTitle = document.createElement("h2");
  cargoTitle.className = "pdf-section-title";
  cargoTitle.textContent = "Foto de cargo";

  const cargo = makeImageBlock(state.cargo[0], { tall: true, defaultCaption: "Registro de cargo" });
  content.append(title, grid, cargoTitle, cargo);
  return page;
}

function buildPagePH(reportCode, formattedDate) {
  const { page, content } = makePageBase(reportCode, formattedDate);
  page.classList.add("pdf-media-page");

  const title = document.createElement("h2");
  title.className = "pdf-section-title";
  title.textContent = "Registro de pH";

  const grid = document.createElement("div");
  const itemCount = Math.max(1, Math.min(2, state.ph.length || 1));
  grid.className = `pdf-grid-dynamic pdf-media-grid count-${itemCount}`;

  if (state.ph.length === 0) {
    grid.append(makeEmptyBlock("No se registraron imagenes de pH."));
  } else if (state.ph.length === 1) {
    grid.append(makeImageBlock(state.ph[0], { defaultCaption: "Registro pH 1" }));
  } else {
    grid.append(
      makeImageBlock(state.ph[0], { defaultCaption: "Registro pH 1" }),
      makeImageBlock(state.ph[1], { defaultCaption: "Registro pH 2" })
    );
  }

  content.append(title, grid);
  return page;
}

function buildDynamicSectionPage(sectionTitle, items, reportCode, formattedDate) {
  const { page, content } = makePageBase(reportCode, formattedDate);
  page.classList.add("pdf-media-page");

  const title = document.createElement("h2");
  title.className = "pdf-section-title";
  title.textContent = sectionTitle;

  const grid = document.createElement("div");
  grid.className = `pdf-grid-dynamic pdf-media-grid count-${items.length}`;

  items.forEach((item) => {
    grid.appendChild(makeImageBlock(item, { defaultCaption: sectionTitle }));
  });

  content.append(title, grid);
  return page;
}

function buildAllPages(data, reportCode, formattedDate) {
  const pages = [
    buildPageOne(data, reportCode, formattedDate),
    buildPagePH(reportCode, formattedDate)
  ];

  if (state.grasa.length > 0) {
    pages.push(buildDynamicSectionPage("Trampas de grasa", state.grasa, reportCode, formattedDate));
  }

  if (state.obs.length > 0) {
    pages.push(buildDynamicSectionPage("Observaciones", state.obs, reportCode, formattedDate));
  }

  const total = pages.length;
  pages.forEach((page, index) => {
    const pageSpan = page.querySelector(".pdf-footer-page");
    if (pageSpan) {
      pageSpan.textContent = `Pagina ${index + 1} de ${total}`;
    }
  });

  return pages;
}

function waitForImages(container) {
  const images = Array.from(container.querySelectorAll("img"));
  return Promise.all(
    images.map((img) => {
      if (img.complete && img.naturalWidth > 0) return Promise.resolve();
      return new Promise((resolve) => {
        img.onload = resolve;
        img.onerror = resolve;
      });
    })
  );
}

async function capturePageImage(page) {
  await waitForImages(page);

  const canvas = await html2canvas(page, {
    scale: 2,
    backgroundColor: "#ffffff"
  });

  return canvas.toDataURL("image/jpeg", 0.9);
}

function showPreview(images) {
  if (!pdfPreviewPanel || !pdfPreviewGrid) return;

  pdfPreviewGrid.innerHTML = "";

  images.forEach((src, index) => {
    const card = document.createElement("article");
    card.className = "preview-item-page";

    const img = document.createElement("img");
    img.src = src;
    img.alt = `Vista previa pagina ${index + 1}`;

    const label = document.createElement("p");
    label.className = "preview-page-label";
    label.textContent = `Pagina ${index + 1}`;

    card.append(img, label);
    pdfPreviewGrid.appendChild(card);
  });

  pdfPreviewPanel.style.display = "block";
}

function downloadBlob(blob, fileName) {
  const blobUrl = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = blobUrl;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  link.remove();
  setTimeout(() => URL.revokeObjectURL(blobUrl), 1000);
}

function generateReportCode() {
  const monthKey = getMonthKey();
  const key = getCounterKey(monthKey);
  const current = Number(storageGet(key) || "0");
  const next = current + 1;
  storageSet(key, String(next));
  updatePreviewCode();
  return formatCode(monthKey, next);
}

function getDraftReportCode() {
  const monthKey = getMonthKey();
  const nextCounter = getNextCounterPreview(monthKey);
  return formatCode(monthKey, nextCounter);
}

function getFormattedDate() {
  return new Intl.DateTimeFormat("es-PE", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).format(new Date());
}

function collectMainData() {
  const data = new FormData(reportForm);
  return {
    cliente: getClienteFinal(),
    ruc: (data.get("ruc") || "").toString().trim(),
    direccion: (data.get("direccion") || "").toString().trim(),
    tecnico: (data.get("tecnico") || "").toString().trim()
  };
}

async function handleGenerate(event) {
  event.preventDefault();
  await generateAndRenderReport({ shouldDownload: true, reserveCode: true });
}

async function generateAndRenderReport(options = {}) {
  const { shouldDownload = false, reserveCode = false } = options;

  if (!reportForm.checkValidity()) {
    reportForm.reportValidity();
    setStatus("Completa los datos principales obligatorios.", "error");
    return;
  }

  if (!requireCargoImage()) return;

  setStatus("Generando informe...");

  try {
    const data = collectMainData();
    if (!data.cliente) {
      setStatus("Selecciona un cliente o escribe uno manual.", "error");
      return;
    }

    const reportCode = reserveCode ? generateReportCode() : getDraftReportCode();
    const formattedDate = getFormattedDate();
    const pages = buildAllPages(data, reportCode, formattedDate);

    pdfRenderRoot.innerHTML = "";
    pages.forEach((page) => pdfRenderRoot.appendChild(page));

    if (!window.jspdf || !window.html2canvas) {
      throw new Error("No se cargaron las librerias de PDF.");
    }

    const { jsPDF } = window.jspdf;
    const pdf = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
    const previewImages = [];

    for (let index = 0; index < pages.length; index += 1) {
      const imageData = await capturePageImage(pages[index]);
      previewImages.push(imageData);
      if (index > 0) pdf.addPage();
      pdf.addImage(imageData, "JPEG", 0, 0, 210, 297, undefined, "FAST");
    }

    const safeClient = sanitizeFilePart(data.cliente);
    const fileName = `Informe_${safeClient}_${reportCode}.pdf`;
    const blob = pdf.output("blob");
    lastGeneratedPdfBlob = blob;
    lastGeneratedFileName = fileName;
    showPreview(previewImages);

    if (shouldDownload) {
      setStatus("Descargando PDF...");
      downloadBlob(blob, fileName);
    }

    setStatus(shouldDownload ? "Informe generado y descargado correctamente." : "Vista previa generada correctamente.", "ok");
  } catch (error) {
    console.error(error);
    setStatus(`Error al generar el informe. ${error?.message || ""}`.trim(), "error");
  } finally {
    pdfRenderRoot.innerHTML = "";
  }
}

async function handlePreviewClick() {
  await generateAndRenderReport({ shouldDownload: false, reserveCode: false });
}

function handleDownloadFromPreview() {
  if (!lastGeneratedPdfBlob || !lastGeneratedFileName) {
    setStatus("Primero genera una vista previa del informe.", "error");
    return;
  }
  setStatus("Descargando PDF...");
  downloadBlob(lastGeneratedPdfBlob, lastGeneratedFileName);
  setStatus("Informe descargado correctamente.", "ok");
}

function handleLogin(event) {
  event.preventDefault();

  if (!loginForm.checkValidity()) {
    loginForm.reportValidity();
    return;
  }

  const user = loginUser.value.trim();
  const pass = loginPass.value.trim();

  if (user === AUTH_USER && pass === AUTH_PASS) {
    sessionSet(AUTH_KEY, "1");
    setLoginStatus("Acceso concedido.", "ok");
    enableReportApp();
  } else {
    setLoginStatus("Credenciales incorrectas.", "error");
  }
}

bindUploaders();
populateClientes();
fillClienteData();
syncClienteRequiredRule();
preloadPdfLogo();
guardAccess();

if (clienteSelect) {
  clienteSelect.addEventListener("change", () => {
    fillClienteData();
    syncClienteRequiredRule();
  });
}

if (clienteManual) {
  clienteManual.addEventListener("input", syncClienteRequiredRule);
}

if (loginForm) {
  loginForm.addEventListener("submit", handleLogin);
}

if (reportForm) {
  reportForm.addEventListener("submit", handleGenerate);
}

if (previewPdfBtn) {
  previewPdfBtn.addEventListener("click", handlePreviewClick);
}

if (downloadFromPreviewBtn) {
  downloadFromPreviewBtn.addEventListener("click", handleDownloadFromPreview);
}
